def _with_dry_run_flag(
    add_arguments: Callable[[argparse.ArgumentParser], None],
) -> Callable[[argparse.ArgumentParser], None]:
    def _add(parser: argparse.ArgumentParser) -> None:
        add_arguments(parser)
        parser.add_argument("--dry-run", action="store_true")

    return _add


def _routine_command_specs() -> list[CommandSpec]:
    specs: list[CommandSpec] = []
    for spec in _routine_command_spec_payloads():
        name = str(spec["name"])
        shortcut = str(spec["shortcut"])
        is_write = spec["risk_level"] == "write"
        add_arguments = _routine_add_arguments(name)
        if is_write:
            add_arguments = _with_dry_run_flag(add_arguments)
        specs.append(
            CommandSpec(
                domain=Domain.ROUTINES,
                shortcut=shortcut if shortcut.startswith("+") else f"+{shortcut}",
                summary=str(spec["summary"]),
                risk_level=spec["risk_level"],
                execution=spec["execution"],
                adapter_tool_name=f"routine_{name.removeprefix('routines.').replace('-', '_')}",
                input_schema=spec["input_schema"],
                output_schema=spec["output_schema"],
                examples=spec["examples"],
                add_arguments=add_arguments,
                build_arguments=_routine_build_arguments(name),
                supports_dry_run=is_write,
            )
        )
    return specs


