def _add_workspace_id_argument(parser: argparse.ArgumentParser) -> None:
    parser.add_argument("--workspace-id")


def _add_routine_list_arguments(parser: argparse.ArgumentParser) -> None:
    _add_workspace_id_argument(parser)
    parser.add_argument("--mode", choices=["ad-hoc"])
    parser.add_argument("--status", choices=["draft", "active", "disabled", "archived"])
    parser.add_argument("--search")
    parser.add_argument("--page", type=int, default=1)
    parser.add_argument("--page-size", type=int, default=20)


def _add_routine_id_arguments(parser: argparse.ArgumentParser) -> None:
    parser.add_argument("--id", dest="routine_id", required=True)
    _add_workspace_id_argument(parser)


def _add_routine_write_arguments(parser: argparse.ArgumentParser) -> None:
    _add_workspace_id_argument(parser)
    parser.add_argument("--name", required=True)
    parser.add_argument("--instruction")
    parser.add_argument("--instruction-file")
    parser.add_argument("--trigger-config-json")
    parser.add_argument("--trigger-config-file")
    parser.add_argument("--idempotency-key")
    _add_routine_target_arguments(parser)


def _add_routine_target_arguments(parser: argparse.ArgumentParser) -> None:
    parser.add_argument(
        "--other-scope-conversation-id",
        help=(
            "Optional Museon chat/scope conversation UUID for an out-of-scope "
            "destination. Use only when the routine result must be delivered to "
            "another chat/channel."
        ),
    )
    parser.add_argument(
        "--result-delivery-mode",
        choices=kebab_choices(ROUTINE_RESULT_DELIVERY_MODES),
        help=(
            "Optional final-result delivery mode. Omit it for source defaults; "
            "defaults to deferred-root-result when "
            "--other-scope-conversation-id is provided."
        ),
    )
    parser.add_argument(
        "--target-conversation-id",
        help=argparse.SUPPRESS,
    )
    parser.add_argument(
        "--target-channel-chat-id",
        help=argparse.SUPPRESS,
    )
    parser.add_argument(
        "--target-delivery-mode",
        choices=kebab_choices(ROUTINE_TARGET_DELIVERY_MODES),
        help=argparse.SUPPRESS,
    )


def _add_routine_rebuild_arguments(parser: argparse.ArgumentParser) -> None:
    parser.add_argument("--id", dest="routine_id", required=True)
    _add_routine_write_arguments(parser)
    parser.add_argument("--memory-content")
    parser.add_argument("--memory-file")
    parser.add_argument("--memory-payload-json")
    parser.add_argument("--memory-payload-file")
    parser.add_argument("--drop-memory", action="store_true")


def _add_routine_record_arguments(parser: argparse.ArgumentParser) -> None:
    parser.add_argument("kind", choices=["output", "memory"])
    parser.add_argument("--id", dest="routine_id", required=True)
    _add_workspace_id_argument(parser)
    parser.add_argument("--content")
    parser.add_argument("--content-file")
    parser.add_argument("--payload-json")
    parser.add_argument("--payload-file")
    parser.add_argument("--idempotency-key")


