async def _execute_rebuild_ad_hoc(ctx: CommandContext) -> Any:
    cfg = ctx.cfg
    arguments = ctx.arguments
    workspace_id = ctx.workspace_id
    api_data = ctx.api_data
    routine_id = str(arguments.get("routine_id") or "")
    has_replacement_memory = (
        arguments.get("memory_content") is not None or arguments.get("memory_file") is not None
    )
    if arguments.get("drop_memory") and has_replacement_memory:
        raise RuntimeError("memory: provide either replacement memory or --drop-memory, not both")
    memory_strategy = (
        "drop" if arguments.get("drop_memory") else "replace" if has_replacement_memory else "copy"
    )
    payload = {
        "workspace_id": workspace_id,
        "name": arguments.get("name"),
        "instruction": read_text_option(
            value=arguments.get("instruction"),
            file_path=arguments.get("instruction_file"),
            field="instruction",
        ),
        "trigger_config": read_json_option(
            value=arguments.get("trigger_config_json"),
            file_path=arguments.get("trigger_config_file"),
            field="trigger_config",
        ),
        "idempotency_key": arguments.get("idempotency_key"),
        "turn_context": routine_turn_context(cfg, arguments=arguments),
        "memory_strategy": memory_strategy,
    }
    if memory_strategy == "replace":
        payload["memory_content"] = read_text_option(
            value=arguments.get("memory_content"),
            file_path=arguments.get("memory_file"),
            field="memory",
        )
        payload["memory_payload"] = read_json_option(
            value=arguments.get("memory_payload_json"),
            file_path=arguments.get("memory_payload_file"),
            field="memory_payload",
            default={},
        )
    elif (
        arguments.get("memory_payload_json") is not None
        or arguments.get("memory_payload_file") is not None
    ):
        raise RuntimeError("memory_payload: provide replacement memory before memory payload")
    data = await api_data(
        cfg,
        "POST",
        f"/agent-cli/routines/{routine_id}/rebuild-ad-hoc",
        json_body=payload,
    )
    return data


